-- Generated SQL for global_unit=3 (stage=1 unit_local=3 unit_id=103)
INSERT INTO `que_choice_py_1` (`q_id`, `unit_id`, `title`, `text`, `options`, `answer`, `hints`, `explanation`, `example`) VALUES

(31, 103, '变量的初识', '在Python中，变量就像贴标签，用来存储数据。以下哪个是正确定义变量的方式？', '[\\\"A. 10 = x\\\", \\\"B. x = 10\\\", \\\"C. var x = 10\\\", \\\"D. let x = 10\\\"]', 'B', '[\\\"提示1：Python中变量赋值使用等号，左边是变量名，右边是值。\\\", \\\"提示2：查看选项，哪个符合''变量名 = 值''的格式？\\\", \\\"提示3：在Python中，不需要关键字如''var''或''let''来声明变量。\\\"]', '正确答案是B。在Python中，变量通过赋值语句定义，格式为''变量名 = 值''。选项A将值放在左边是错误的；选项C和D使用了其他语言的语法，Python中不需要。', '例如，定义一个变量存储年龄：age = 25'),
(32, 103, '命名规则大考验', 'Python变量名有自己的规则，就像给宠物起名不能叫''狗''一样。以下哪个是有效的变量名？', '[\\\"A. 123var\\\", \\\"B. _temp\\\", \\\"C. my-var\\\", \\\"D. for\\\"]', 'B', '[\\\"提示1：变量名必须以字母或下划线开头。\\\", \\\"提示2：变量名只能包含字母、数字和下划线。\\\", \\\"提示3：不能使用Python保留字作为变量名。\\\"]', '正确答案是B。''_temp''以字母或下划线开头，只包含字母、数字、下划线。A以数字开头无效；C包含连字符无效；D是保留字无效。', '有效变量名示例：_count, total_sum, age2'),
(33, 103, '大小写敏感', 'Python是大小写敏感的语言，''Name''和''name''是两个不同的变量。以下哪个说法正确？', '[\\\"A. 变量名可以以数字开头\\\", \\\"B. 变量名区分大小写\\\", \\\"C. 变量名可以包含空格\\\", \\\"D. 变量名可以是任何字符\\\"]', 'B', '[\\\"提示1：回顾Python变量命名规则。\\\", \\\"提示2：想想''myVar''和''myvar''是否相同。\\\", \\\"提示3：检查每个选项是否符合规则。\\\"]', '正确答案是B。Python变量名区分大小写，所以''Name''和''name''是不同的。A错误，不能以数字开头；C错误，不能包含空格；D错误，只能包含字母、数字、下划线。', '例如，x = 5 和 X = 10 是两个不同的变量。'),
(36, 103, '保留字禁区', 'Python有一些保留字，就像交通标志不能用作车牌号一样。以下哪个是Python的保留字？', '[\\\"A. variable\\\", \\\"B. data\\\", \\\"C. for\\\", \\\"D. value\\\"]', 'C', '[\\\"提示1：保留字是Python语言中具有特殊意义的单词。\\\", \\\"提示2：常见保留字包括if, else, for, while等。\\\", \\\"提示3：检查选项，哪个是用于控制流程的关键字？\\\"]', '正确答案是C。''for''是Python的保留字，用于循环。其他选项不是保留字。', '其他保留字示例：if, else, while, def, class'),
(37, 103, '命名风格', '在Python中，变量名通常使用小写字母和下划线，这被称为snake_case。以下哪个符合Python的命名惯例？', '[\\\"A. myVariable\\\", \\\"B. my_variable\\\", \\\"C. MyVariable\\\", \\\"D. MYVARIABLE\\\"]', 'B', '[\\\"提示1：Python推荐使用snake_case命名变量。\\\", \\\"提示2：snake_case使用小写字母和下划线分隔单词。\\\", \\\"提示3：查看选项，哪个使用小写和下划线？\\\"]', '正确答案是B。''my_variable''使用小写字母和下划线，符合Python的命名惯例。A是camelCase，C是PascalCase，D是常量风格（但变量通常不用全大写）。', '惯例示例：user_name, total_count, is_valid'),
(38, 103, '错误变量名', '以下哪个变量名会导致Python语法错误？', '[\\\"A. _private\\\", \\\"B. 2nd_place\\\", \\\"C. class_name\\\", \\\"D. variable123\\\"]', 'B', '[\\\"提示1：变量名不能以数字开头。\\\", \\\"提示2：检查每个选项是否符合命名规则。\\\", \\\"提示3：''2nd_place''以数字开头，是无效的。\\\"]', '正确答案是B。''2nd_place''以数字开头，违反了变量命名规则，会导致SyntaxError。其他选项都是有效的：A以下划线开头有效，C使用保留字''class''但作为一部分有效（class_name不是保留字），D以字母开头有效。', '有效变量名不能以数字开头，如''place2''是有效的，但''2place''无效。'),
(41, 103, '变量名长度', 'Python变量名可以有多长？以下说法正确的是：', '[\\\"A. 最多8个字符\\\", \\\"B. 最多255个字符\\\", \\\"C. 没有固定限制，但应保持合理\\\", \\\"D. 必须至少3个字符\\\"]', 'C', '[\\\"提示1：Python对变量名长度没有硬性限制。\\\", \\\"提示2：但为了可读性，应该保持简洁。\\\", \\\"提示3：查看Python官方文档或常见实践。\\\"]', '正确答案是C。Python变量名长度没有固定限制，但为了代码可读性和维护性，应该使用有意义的、合理长度的名称。', '例如，''index''比''i''更清晰，但''this_is_a_very_long_variable_name_that_is_hard_to_read''可能过长。'),
(42, 103, '特殊变量名', '在Python中，以下哪个变量名是常见的约定，用于表示私有变量？', '[\\\"A. private_var\\\", \\\"B. __var__\\\", \\\"C. _var\\\", \\\"D. var_private\\\"]', 'C', '[\\\"提示1：Python中没有真正的私有变量，但有些约定。\\\", \\\"提示2：单下划线开头表示保护或内部使用。\\\", \\\"提示3：双下划线开头用于名称修饰。\\\"]', '正确答案是C。单下划线开头的变量名（如_var）通常表示这是一个保护变量，用于内部使用，但并不是强制的。双下划线开头（如__var__）通常用于特殊方法。', '例如，在类中，_protected_var 表示受保护的属性。'),
(43, 103, '语法错误识别', '以下哪段代码会导致SyntaxError？', '[\\\"A. x = 10\\\", \\\"B. 123 = x\\\", \\\"C. _y = 20\\\", \\\"D. z1 = 30\\\"]', 'B', '[\\\"提示1：SyntaxError通常由于语法违反规则。\\\", \\\"提示2：检查赋值语句的左边是否有效变量名。\\\", \\\"提示3：变量名不能以数字开头。\\\"]', '正确答案是B。''123 = x''试图将值赋给数字，这是无效的，因为左边必须是变量名。其他选项都是有效的赋值。', '有效赋值：a = 5; _temp = 10; var2 = 15');

INSERT INTO `que_fill_py_1` (`q_id`, `unit_id`, `title`, `text`, `input`, `output`, `code`, `options`, `answer`, `explanation`, `example`) VALUES

(34, 103, '有效变量名填空', '代码中需要定义一个变量，但变量名部分缺失。请从选项中选择一个有效的变量名填入。', NULL, NULL, '[{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" = 10\\\"}]}]', '[\\\"123abc\\\", \\\"_count\\\", \\\"my-var\\\", \\\"for\\\", \\\"total score\\\"]', '[1]', '正确答案是''_count''，因为它以字母或下划线开头，只包含字母、数字、下划线。其他选项无效：''123abc''以数字开头，''my-var''包含连字符，''for''是保留字，''total score''包含空格。', '有效变量名示例：age, _temp, user_name2'),
(35, 103, '变量赋值游戏', '小华在写代码时，不小心把赋值语句弄乱了。请帮助他填空，使代码正确运行。', NULL, '[\\\"15\\\"]', '[{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"x = 5\n\\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" = 10\nprint(x + \\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":1},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\")\\\"}]}]', '[\\\"y\\\", \\\"5\\\", \\\"10\\\", \\\"15\\\", \\\"x\\\"]', '[0, 0]', '将变量名''y''赋值为10后，代码为''x = 5\ny = 10\nprint(x + y)''，计算5+10=15并打印。其他选项如数字不能作为变量名左边。', '类似地，可以定义变量a和b：a = 3; b = 7; print(a + b)'),
(39, 103, '有效变量填空', '代码需要定义并打印一个变量。请从选项中选择有效的变量名填空。', NULL, '[\\\"10\\\"]', '[{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" = 10\\\"}]},{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"print(\\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":1},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\")\\\"}]}]', '[\\\"var1\\\", \\\"2ndVar\\\", \\\"_data\\\", \\\"my.data\\\", \\\"while\\\"]', '[2, 2]', '变量名''_data''是有效的，它以字母或下划线开头，只包含字母、数字、下划线。填空后代码为''_data = 10''和''print(_data)''，正确打印10。其他选项无效：''2ndVar''以数字开头，''my.data''包含点，''while''是保留字。', '类似地，可以使用其他有效变量名，如''count''或''_temp''。'),
(40, 103, '变量运算填空', '代码计算两个变量的和，但部分变量名缺失。请填空使代码正确且符合命名规则。', NULL, '[\\\"8\\\"]', '[{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" = 5\\\"}]},{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"slot\\\",\\\"index\\\":1},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" = 3\\\"}]},{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"result = \\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":2},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" + \\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":3},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"\nprint(result)\\\"}]}]', '[\\\"a\\\", \\\"b\\\", \\\"c\\\", \\\"num1\\\", \\\"num2\\\", \\\"sum\\\", \\\"5\\\", \\\"3\\\", \\\"8\\\"]', '[0, 1, 0, 1]', '定义变量''a''和''b''分别赋值为5和3，然后计算result = a + b，打印8。使用简短有效的变量名使代码清晰。', '多变量赋值示例：x, y = 10, 20; total = x + y'),
(44, 103, '变量名规范填空', '代码中定义了几个变量，但有些变量名不符合规范。请从选项中选择符合规范的变量名填空。', NULL, '[\\\"3\\\"]', '[{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" = 1\\\"}]},{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"slot\\\",\\\"index\\\":1},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" = 2\\\"}]},{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"print(\\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":2},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" + \\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":3},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\")\\\"}]}]', '[\\\"A\\\", \\\"myVar\\\", \\\"my_var\\\", \\\"MY_VAR\\\", \\\"a\\\", \\\"b\\\"]', '[4, 2, 4, 2]', '根据Python命名惯例，变量名应使用小写字母和snake_case。所以填空为''a''和''my_var''，代码为''a = 1\nmy_var = 2\nprint(a + my_var)''，计算1+2=3并打印。', '规范命名：user_name, is_valid, total_count'),
(45, 103, '完整代码填空', '以下代码模拟简单计算，但变量名部分缺失。请填空使代码正确且符合命名规则。', NULL, '[\\\"50\\\"]', '[{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" = 30\\\"}]},{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"slot\\\",\\\"index\\\":1},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" = 20\\\"}]},{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"sum = \\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":2},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\" + \\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":3},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"\nprint(sum)\\\"}]}]', '[\\\"num1\\\", \\\"num2\\\", \\\"price\\\", \\\"quantity\\\", \\\"30\\\", \\\"20\\\", \\\"50\\\"]', '[0, 1, 0, 1]', '使用描述性的变量名''num1''和''num2''，代码为''num1 = 30\nnum2 = 20\nsum = num1 + num2\nprint(sum)''，计算30+20=50并打印。', '类似地，可以定义''price''和''quantity''来计算总价：price = 10; quantity = 5; total = price * quantity');